
#include "snp_pmu.h"
#include "lib_snip_transform.h"
#include <assert.h>
#include "et_test_env.h" //autogenerated by Sting. Can be found under 'build' dir

unum_t snp_get_pmu_event(CpuResource * cpu_resource, unum_t cntr_id) {
   unum_t event_base = ET_TEST_ENV.PMU_EVENT_BASE;
   unum_t event_type;
   unum_t tail;
   const unum_t min_events[10] = {11, 13, 18, 19, 20, 21, 22, 23, 24, 25};
   const unum_t neigh_events_coop[17] = {1, 2, 3, 4, 5, 6, 7, 8, 9};
   const unum_t neigh_events[17] = {12, 13, 14, 15, 16, 21, 22, 23};
   if (cntr_id <= 6) {
      assert(cntr_id >= 3);
      event_type = (event_base * 4) + (cntr_id - 3);
      if (event_type >= 10) {
         event_type = event_type % 10;
      }
      return min_events[event_type];
   }
   else {
      assert(cntr_id <= 8);
      event_type = (event_base * 2) + (cntr_id - 7);
      if (event_type >= 17) {
         event_type = event_type % 17;
      }
      if (ET_TEST_ENV.COOP_MODE_ENABLE == 1) {
         return neigh_events_coop[event_type];
      } else {
         return neigh_events[event_type];
      }
   }
}
